/// <summary>
/// The ETGSalesOrderWFApprovalResubmitActionMgr menu item action event handler.
/// </summary>
public class ETGSalesOrderWFApprovalResubmitActionMgr 
{
    SalesTable salesTable;
}

Method.Source:
    public static void main(Args args)
	{
        RecID                           recID = args.record().RecId;
        SalesTable                      salesTableLoc = args.record();;
        WorkflowWorkItemTable           workItem = args.caller().getActiveWorkflowWorkItem();
        WorkflowWorkItemActionDialog    workflowWorkItemActionDialog;

        if (workItem.RecId > 0)
        {
            try
            {
                workflowWorkItemActionDialog = WorkflowWorkItemActionDialog::construct( workItem,
                    WorkflowWorkItemActionType::Resubmit,
                    new MenuFunction(args.menuItemName(),args.menuItemType()));
                workflowWorkItemActionDialog.run();

                if (workflowWorkItemActionDialog.parmIsClosedOK())
                {
                    workItem = args.caller().getActiveWorkflowWorkItem();
                    WorkflowWorkItemActionManager::dispatchWorkItemAction(workItem,
                                                                    workflowWorkItemActionDialog.parmWorkflowComment(),
                                                                    workflowWorkItemActionDialog.parmTargetUser(),
                                                                    WorkflowWorkItemActionType::Resubmit,
                                                                    args.menuItemName(),
                                                                    'False');
                    ETGSalesOrderWFApprovalResubmitActionMgr::newSalesOrder(salesTableLoc).createResubmit();
                }
                else
                {
                    throw Exception::Error;
                }
            }
            catch(Exception::Error)
            {
                throw error(strfmt("Error. Can not resubmit"));
            }
        }
    }

public static ETGSalesOrderWFApprovalResubmitActionMgr newSalesOrder(SalesTable _salesTable)
{
    ETGSalesOrderWFApprovalResubmitActionMgr resubmit = ETGSalesOrderWFApprovalResubmitActionMgr::construct();
    resubmit.parmSales(_salesTable);
    return resubmit;
}

/// <summary>
/// Construct method
/// </summary>
/// <returns>new instance of ETGSalesOrderWFApprovalResubmitActionMgr</returns>
protected static ETGSalesOrderWFApprovalResubmitActionMgr construct()
{
    return new ETGSalesOrderWFApprovalResubmitActionMgr();
}

/// <summary>
/// parameter method for SalesTable
/// </summary>
/// <param name = "_salesTable">salesTable value</param>
/// <returns>salesTable value</returns>
protected SalesTable parmSales(SalesTable _salesTable = salesTable)
{
    salesTable = _salesTable;

    return salesTable;
}

/// <summary>
/// 
/// </summary>
public void createResubmit()
{
    salesTable = this.parmSales();

    ttsbegin;

    //if(salesTable.())
    //{
        if(salesTable.ETGWorkflowStatus == VersioningDocumentState::Rejected || salesTable.ETGWorkflowStatus == VersioningDocumentState::InReview)
        {
            salesTable::updateWorkflowStatus(salesTable.RecId, VersioningDocumentState::InReview);
        }
   // }

